// AuthServiceServer is the server API for AuthService service.
// All implementations must embed UnimplementedAuthServiceServer
// for forward compatibility.
type AuthServiceServer interface {
	//
	// 인증 (Authentication)
	//
	Login(context.Context, *LoginRequest) (*LoginResponse, error)
	ValidateToken(context.Context, *ValidateTokenRequest) (*ValidateTokenResponse, error)
	RefreshToken(context.Context, *RefreshTokenRequest) (*RefreshTokenResponse, error)
	//
	// 사용자 관리 (User Management)
	//
	CreateUser(context.Context, *CreateUserRequest) (*CreateUserResponse, error)
	BatchCreateUsers(context.Context, *BatchCreateUsersRequest) (*BatchCreateUsersResponse, error)
	GetUser(context.Context, *GetUserRequest) (*GetUserResponse, error)
	ListUsers(context.Context, *ListUsersRequest) (*ListUsersResponse, error)
	UpdateUser(context.Context, *UpdateUserRequest) (*UpdateUserResponse, error)
	DeleteUser(context.Context, *DeleteUserRequest) (*DeleteUserResponse, error)
	//
	// 테넌트 관리 (Tenant Management)
	//
	CreateTenant(context.Context, *CreateTenantRequest) (*CreateTenantResponse, error)
	GetTenant(context.Context, *GetTenantRequest) (*GetTenantResponse, error)
	ListTenants(context.Context, *ListTenantsRequest) (*ListTenantsResponse, error)
	//
	// 부서 관리 (Department Management)
	//
	CreateDepartment(context.Context, *CreateDepartmentRequest) (*CreateDepartmentResponse, error)
	BatchCreateDepartments(context.Context, *BatchCreateDepartmentsRequest) (*BatchCreateDepartmentsResponse, error)
	ListDepartments(context.Context, *ListDepartmentsRequest) (*ListDepartmentsResponse, error)
	UpdateDepartment(context.Context, *UpdateDepartmentRequest) (*UpdateDepartmentResponse, error)
	DeleteDepartment(context.Context, *DeleteDepartmentRequest) (*DeleteDepartmentResponse, error)
	GetDepartment(context.Context, *GetDepartmentRequest) (*GetDepartmentResponse, error)
	ReorderDepartments(context.Context, *ReorderDepartmentsRequest) (*ReorderDepartmentsResponse, error)
	//
	// 프로젝트 관리 (Project Management)
	//
	CreateProject(context.Context, *CreateProjectRequest) (*CreateProjectResponse, error)
	BatchCreateProjects(context.Context, *BatchCreateProjectsRequest) (*BatchCreateProjectsResponse, error)
	ListProjects(context.Context, *ListProjectsRequest) (*ListProjectsResponse, error)
	UpdateProject(context.Context, *UpdateProjectRequest) (*UpdateProjectResponse, error)
	DeleteProject(context.Context, *DeleteProjectRequest) (*DeleteProjectResponse, error)
	GetProject(context.Context, *GetProjectRequest) (*GetProjectResponse, error)
	ReorderProjects(context.Context, *ReorderProjectsRequest) (*ReorderProjectsResponse, error)
	//
	// Position & Job Management
	//
	CreatePosition(context.Context, *CreatePositionRequest) (*CreatePositionResponse, error)
	ListPositions(context.Context, *ListPositionsRequest) (*ListPositionsResponse, error)
	UpdatePosition(context.Context, *UpdatePositionRequest) (*UpdatePositionResponse, error)
	DeletePosition(context.Context, *DeletePositionRequest) (*DeletePositionResponse, error)
	ReorderPositions(context.Context, *ReorderPositionsRequest) (*ReorderPositionsResponse, error)
	BatchCreatePositions(context.Context, *BatchCreatePositionsRequest) (*BatchCreatePositionsResponse, error)
	//
	// ACL - Access Control
	//
	CheckAccess(context.Context, *CheckAccessRequest) (*CheckAccessResponse, error)
	RequestAccess(context.Context, *RequestAccessRequest) (*RequestAccessResponse, error)
	GrantAccess(context.Context, *GrantAccessRequest) (*GrantAccessResponse, error)
	ListAccessRequests(context.Context, *ListAccessRequestsRequest) (*ListAccessRequestsResponse, error)
	//
	// Advanced ACL - Visibility & Metadata
	//
	CreateDocumentMetadata(context.Context, *CreateDocumentMetadataRequest) (*CreateDocumentMetadataResponse, error)
	UpdateDocumentVisibility(context.Context, *UpdateDocumentVisibilityRequest) (*UpdateDocumentVisibilityResponse, error)
	GetDocumentMetadata(context.Context, *GetDocumentMetadataRequest) (*GetDocumentMetadataResponse, error)
	//
	// Advanced ACL - Visibility Approval
	//
	ListVisibilityApprovals(context.Context, *ListVisibilityApprovalsRequest) (*ListVisibilityApprovalsResponse, error)
	ApproveVisibilityChange(context.Context, *ApproveVisibilityChangeRequest) (*ApproveVisibilityChangeResponse, error)
	//
	// Password Management
	//
	ResetAndSendPassword(context.Context, *ResetAndSendPasswordRequest) (*ResetAndSendPasswordResponse, error)
	BatchResetPassword(context.Context, *BatchResetPasswordRequest) (*BatchResetPasswordResponse, error)
	mustEmbedUnimplementedAuthServiceServer()
}

